     1→"use client";
     2→
     3→import { Suspense } from "react";
     4→import dynamic from "next/dynamic";
     5→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
     6→import { QRCodeSVG } from "qrcode.react";
     7→import { useCamera } from "@/hooks/useCamera";
     8→import { useGestureRecognizer } from "@/hooks/useGestureRecognizer";
     9→import { usePoseDetection } from "@/hooks/usePoseDetection";
    10→import { useOrbAvatar } from "@/hooks/useOrbAvatar";
    11→import { useDeepgramSTT } from "@/hooks/useDeepgramSTT";
    12→import { parseEmotionTag } from "@/lib/emotion-parser";
    13→import { GestureIndicator } from "@/components/mirror/GestureIndicator";
    14→import { ClothingCanvas } from "@/components/mirror/ClothingCanvas";
    15→import VoiceIndicator from "@/components/mirror/VoiceIndicator";
    16→import PriceStrip, { type PriceStripItem } from "@/components/mirror/PriceStrip";
    17→import { socket } from "@/lib/socket";
    18→import { skipQueueUser, startMirrorSession } from "@/lib/api";
    19→import type { DetectedGesture, GestureType } from "@/types/gestures";
    20→import type { PoseResult } from "@/types/pose";
    21→import type { ClothingItem } from "@/types/clothing";
    22→import { mapToClothingItems } from "@/lib/map-clothing-items";
    23→
    24→// Lazy-load the Orb (Three.js is heavy — don't block initial paint)
    25→const Orb = dynamic(
    26→  () => import("@/components/ui/orb").then((mod) => ({ default: mod.Orb })),
    27→  { ssr: false },
    28→);
    29→
    30→type KioskState = "attract" | "waiting" | "session";
    31→
    32→interface ActiveUser {
    33→  id: string;
    34→  name: string;
    35→}
    36→
    37→const PHONE_URL = process.env.NEXT_PUBLIC_PHONE_URL || "https://mirrorless.vercel.app/phone";
    38→const WAITING_TIMEOUT_MS = 2 * 60 * 1000; // 2 minutes
    39→
    40→export default function MirrorPageWrapper() {
    41→  return (
    42→    <Suspense fallback={null}>
    43→      <MirrorPage />
    44→    </Suspense>
    45→  );
    46→}
    47→
    48→function MirrorPage() {
    49→  // Kiosk state
    50→  const [kioskState, setKioskState] = useState<KioskState>("attract");
    51→  const [activeUser, setActiveUser] = useState<ActiveUser | null>(null);
    52→  const waitingTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    53→
    54→  // Camera + gesture recognition
    55→  const { videoRef, isReady: isCameraReady, error: cameraError } = useCamera();
    56→  const [lastGesture, setLastGesture] = useState<GestureType | null>(null);
    57→  const gestureKeyRef = useRef(0);
    58→  const [gestureKey, setGestureKey] = useState(0);
    59→
    60→  // Session state
    61→  const [sessionActive, setSessionActive] = useState(false);
    62→  const [isStarting, setIsStarting] = useState(false);
    63→
    64→  // Pose detection + clothing overlay state
    65→  const [currentPose, setCurrentPose] = useState<PoseResult | null>(null);
    66→
    67→  interface CanvasOutfit {
    68→    name: string;
    69→    items: ClothingItem[];
    70→    productInfo: PriceStripItem[];
    71→  }
    72→  const [canvasOutfits, setCanvasOutfits] = useState<CanvasOutfit[]>([]);
    73→  const [canvasOutfitIndex, setCanvasOutfitIndex] = useState(0);
    74→  const activeCanvasOutfit = canvasOutfits[canvasOutfitIndex]?.items ?? [];
    75→  const activePriceItems = canvasOutfits[canvasOutfitIndex]?.productInfo ?? [];
    76→
    77→  // Orb avatar + voice
    78→  const orb = useOrbAvatar();
    79→  const stt = useDeepgramSTT();
    80→
    81→  // Queue transcripts while orb is speaking, send when quiet
    82→  const pendingTranscriptRef = useRef<string | null>(null);
    83→
    84→  // Accumulate full response text before delivering
    85→  const responseAccumulatorRef = useRef<string>("");
    86→
    87→  // Current user ID for session (from queue, not URL)
    88→  const userId = activeUser?.id ?? null;
    89→
    90→  // Pose detection for clothing overlay
    91→  const handlePoseUpdate = useCallback((result: PoseResult) => {
    92→    setCurrentPose(result);
    93→  }, []);
    94→
    95→  usePoseDetection({
    96→    videoRef,
    97→    isVideoReady: isCameraReady,
    98→    onPoseUpdate: handlePoseUpdate,
    99→  });
   100→
   101→  // Connect socket and join mirror room
   102→  useEffect(() => {
   103→    socket.connect();
   104→    socket.emit("join_mirror_room");
   105→
   106→    return () => {
   107→      socket.disconnect();
   108→    };
   109→  }, []);
   110→
   111→  // Join user-specific room when active user changes
   112→  useEffect(() => {
   113→    if (userId) {
   114→      socket.emit("join_room", { user_id: userId });
   115→    }
   116→  }, [userId]);
   117→
   118→  // Listen for queue_updated events (drives attract ↔ waiting transitions)
   119→  useEffect(() => {
   120→    const handleQueueUpdated = (data: {
   121→      active_user: ActiveUser | null;
   122→      queue: Array<{ id: string; user_id: string; name: string; position: number; status: string }>;
   123→    }) => {
   124→      console.log("[Mirror] queue_updated:", data);
   125→      if (kioskState === "session") return; // Don't interrupt active sessions
   126→
   127→      if (data.active_user) {
   128→        setActiveUser(data.active_user);
   129→        setKioskState("waiting");
   130→      } else {
   131→        setActiveUser(null);
   132→        setKioskState("attract");
   133→      }
   134→    };
   135→
   136→    socket.on("queue_updated", handleQueueUpdated);
   137→    return () => {
   138→      socket.off("queue_updated", handleQueueUpdated);
   139→    };
   140→  }, [kioskState]);
   141→
   142→  // 2-minute timeout in waiting state
   143→  useEffect(() => {
   144→    if (kioskState === "waiting" && activeUser) {
   145→      waitingTimerRef.current = setTimeout(() => {
   146→        console.log("[Mirror] Waiting timeout — auto-skipping user");
   147→        skipQueueUser(activeUser.id).catch(() => {});
   148→      }, WAITING_TIMEOUT_MS);
   149→    }
   150→    return () => {
   151→      if (waitingTimerRef.current) {
   152→        clearTimeout(waitingTimerRef.current);
   153→        waitingTimerRef.current = null;
   154→      }
   155→    };
   156→  }, [kioskState, activeUser]);
   157→
   158→  // Listen for session_active from backend
   159→  useEffect(() => {
   160→    const handleSessionActive = () => {
   161→      setKioskState("session");
   162→      setSessionActive(true);
   163→      setIsStarting(false);
   164→      setCanvasOutfits([]);
   165→      setCanvasOutfitIndex(0);
   166→      orb.startSession();
   167→      stt.startListening();
   168→    };
   169→
   170→    socket.on("session_active", handleSessionActive);
   171→    return () => {
   172→      socket.off("session_active", handleSessionActive);
   173→    };
   174→    // eslint-disable-next-line react-hooks/exhaustive-deps
   175→  }, []);
   176→
   177→  // Listen for mira_speech events (streamed text from AI)
   178→  useEffect(() => {
   179→    const handleSpeech = (data: { text?: string; is_chunk?: boolean }) => {
   180→      // Fallback session detection
   181→      if (!sessionActive && !isStarting) {
   182→        setKioskState("session");
   183→        setSessionActive(true);
   184→        setIsStarting(false);
   185→        orb.startSession();
   186→        stt.startListening();
   187→      }
   188→
   189→      if (data.is_chunk !== false) {
   190→        if (!data.text) return;
   191→        console.log("[Mirror] mira_speech chunk received");
   192→        responseAccumulatorRef.current += data.text;
   193→        orb.setOrbState("thinking");
   194→      } else {
   195→        if (data.text) {
   196→          responseAccumulatorRef.current += data.text;
   197→        }
   198→        const fullText = responseAccumulatorRef.current;
   199→        responseAccumulatorRef.current = "";
   200→        console.log("[Mirror] Agent full response:", fullText);
   201→        if (!fullText) return;
   202→
   203→        const { emotion, cleanText } = parseEmotionTag(fullText);
   204→        console.log("[Mirror] Parsed emotion:", emotion);
   205→        orb.speak(cleanText, emotion);
   206→      }
   207→    };
   208→
   209→    socket.on("mira_speech", handleSpeech);
   210→    return () => {
   211→      socket.off("mira_speech", handleSpeech);
   212→    };
   213→    // eslint-disable-next-line react-hooks/exhaustive-deps
   214→  }, [sessionActive, isStarting]);
   215→
   216→  // Listen for tool_result events (product recommendations + voice messages)
   217→  useEffect(() => {
   218→    const handleToolResult = (data: {
   219→      type?: string;
   220→      tool?: string;
   221→      items?: { title: string; price?: string; [key: string]: unknown }[];
   222→      text?: string;
   223→      emotion?: string;
   224→      outfit_name?: string;
   225→    }) => {
   226→      if (data.type === "display_product" && data.items) {
   227→        const clothingItems = mapToClothingItems(data.items);
   228→        const priceInfo: PriceStripItem[] = data.items.map((it) => ({
   229→          title: it.title,
   230→          price: it.price,
   231→        }));
   232→        if (clothingItems.length > 0) {
   233→          setCanvasOutfits((prev) => {
   234→            const next = [...prev, {
   235→              name: data.outfit_name || `Outfit ${prev.length + 1}`,
   236→              items: clothingItems,
   237→              productInfo: priceInfo,
   238→            }];
   239→            setCanvasOutfitIndex(next.length - 1);
   240→            return next;
   241→          });
   242→        }
   243→        return;
   244→      }
   245→      if (data.type === "voice_message" && data.text) {
   246→        orb.speak(data.text);
   247→        return;
   248→      }
   249→    };
   250→
   251→    socket.on("tool_result", handleToolResult);
   252→    return () => {
   253→      socket.off("tool_result", handleToolResult);
   254→    };
   255→    // eslint-disable-next-line react-hooks/exhaustive-deps
   256→  }, [orb.speak]);
   257→
   258→  // Listen for session_ended — return to attract or waiting
   259→  useEffect(() => {
   260→    const handleSessionEnded = () => {
   261→      orb.stopSession();
   262→      stt.stopListening();
   263→      setSessionActive(false);
   264→      setCanvasOutfits([]);
   265→      setCanvasOutfitIndex(0);
   266→      setActiveUser(null);
   267→      setKioskState("attract");
   268→      // Queue advancement happens server-side, queue_updated will fire next
   269→    };
   270→
   271→    socket.on("session_ended", handleSessionEnded);
   272→    return () => {
   273→      socket.off("session_ended", handleSessionEnded);
   274→    };
   275→    // eslint-disable-next-line react-hooks/exhaustive-deps
   276→  }, []);
   277→
   278→  // Listen for session_force_end — same as session_ended
   279→  useEffect(() => {
   280→    const handleForceEnd = (data: { user_id?: string }) => {
   281→      if (userId && data.user_id === userId) {
   282→        socket.emit("end_session", { user_id: userId });
   283→      }
   284→    };
   285→
   286→    socket.on("session_force_end", handleForceEnd);
   287→    return () => {
   288→      socket.off("session_force_end", handleForceEnd);
   289→    };
   290→  }, [userId]);
   291→
   292→  // Send transcripts to backend when orb stops speaking
   293→  useEffect(() => {
   294→    if (!orb.isSpeaking && pendingTranscriptRef.current && userId) {
   295→      console.log("[Mirror] Flushing queued transcript:", pendingTranscriptRef.current);
   296→      socket.emit("mirror_event", {
   297→        user_id: userId,
   298→        event: { type: "voice", transcript: pendingTranscriptRef.current },
   299→      });
   300→      pendingTranscriptRef.current = null;
   301→    }
   302→  }, [orb.isSpeaking, userId]);
   303→
   304→  // Forward final STT transcripts
   305→  useEffect(() => {
   306→    if (!stt.transcript || !userId) return;
   307→
   308→    if (orb.isSpeaking) {
   309→      console.log("[Mirror] Queuing transcript (orb speaking):", stt.transcript);
   310→      pendingTranscriptRef.current = stt.transcript;
   311→    } else {
   312→      console.log("[Mirror] Sending transcript to backend:", stt.transcript);
   313→      socket.emit("mirror_event", {
   314→        user_id: userId,
   315→        event: { type: "voice", transcript: stt.transcript },
   316→      });
   317→    }
   318→    // eslint-disable-next-line react-hooks/exhaustive-deps
   319→  }, [stt.transcript, userId]);
   320→
   321→  // Listen for snapshot requests from the backend
   322→  useEffect(() => {
   323→    const handleSnapshotRequest = () => {
   324→      const video = videoRef.current;
   325→      if (!video || video.readyState < video.HAVE_CURRENT_DATA) return;
   326→
   327→      const canvas = document.createElement("canvas");
   328→      canvas.width = video.videoWidth;
   329→      canvas.height = video.videoHeight;
   330→      const ctx = canvas.getContext("2d");
   331→      if (!ctx) return;
   332→
   333→      ctx.drawImage(video, 0, 0);
   334→      const dataUrl = canvas.toDataURL("image/jpeg", 0.7);
   335→      const base64 = dataUrl.split(",")[1];
   336→
   337→      socket.emit("mirror_event", {
   338→        type: "snapshot",
   339→        image_base64: base64,
   340→        user_id: userId,
   341→      });
   342→    };
   343→
   344→    socket.on("request_snapshot", handleSnapshotRequest);
   345→    return () => {
   346→      socket.off("request_snapshot", handleSnapshotRequest);
   347→    };
   348→  }, [videoRef, userId]);
   349→
   350→  // Gesture handler
   351→  const handleGesture = useCallback(
   352→    (gesture: DetectedGesture) => {
   353→      console.log("[Mirror] Gesture detected:", gesture.type, gesture.confidence);
   354→
   355→      setLastGesture(gesture.type);
   356→      gestureKeyRef.current += 1;
   357→      setGestureKey(gestureKeyRef.current);
   358→
   359→      if (canvasOutfits.length > 1) {
   360→        if (gesture.type === "swipe_left") {
   361→          setCanvasOutfitIndex((i) => (i + 1) % canvasOutfits.length);
   362→        } else if (gesture.type === "swipe_right") {
   363→          setCanvasOutfitIndex((i) => (i - 1 + canvasOutfits.length) % canvasOutfits.length);
   364→        }
   365→      }
   366→
   367→      socket.emit("mirror_event", {
   368→        user_id: userId,
   369→        event: {
   370→          type: "gesture",
   371→          gesture: gesture.type,
   372→          confidence: gesture.confidence,
   373→          timestamp: gesture.timestamp,
   374→        },
   375→      });
   376→    },
   377→    [userId, canvasOutfits.length],
   378→  );
   379→
   380→  const { isLoading: isModelLoading, error: modelError } =
   381→    useGestureRecognizer({
   382→      videoRef,
   383→      isVideoReady: isCameraReady,
   384→      onGesture: handleGesture,
   385→    });
   386→
   387→  const handleStartSession = useCallback(() => {
   388→    if (!userId || isStarting || sessionActive) return;
   389→
   390→    // Unlock browser audio policy while we still have the user gesture context
   391→    const ctx = new AudioContext();
   392→    ctx.resume().then(() => ctx.close());
   393→
   394→    setIsStarting(true);
   395→
   396→    // Emit start via socket (server-side orchestrator)
   397→    socket.emit("start_session", { user_id: userId });
   398→  }, [userId, isStarting, sessionActive]);
   399→
   400→  const handleSkipUser = useCallback(() => {
   401→    if (!activeUser) return;
   402→    skipQueueUser(activeUser.id).catch(() => {});
   403→  }, [activeUser]);
   404→
   405→  // Context-aware orb positioning
   406→  const orbStyle = useMemo<React.CSSProperties>(() => {
   407→    const hasProducts = canvasOutfits.length > 0;
   408→    if (orb.orbState === "idle") {
   409→      return { top: 24, right: 24, width: 120, height: 120 };
   410→    }
   411→    if (orb.orbState === "thinking") {
   412→      return { top: "35%", left: "50%", transform: "translateX(-50%)", width: 180, height: 180 };
   413→    }
   414→    if (hasProducts) {
   415→      return { top: 24, right: 24, width: 150, height: 150 };
   416→    }
   417→    return { top: "25%", right: 40, width: 200, height: 200 };
   418→  }, [orb.orbState, canvasOutfits.length]);
   419→
   420→  return (
   421→    <main
   422→      style={{
   423→        position: "relative",
   424→        width: "100vw",
   425→        height: "100vh",
   426→        background: "#000",
   427→        overflow: "hidden",
   428→      }}
   429→    >
   430→      {/* Webcam feed (mirrored) */}
   431→      <video
   432→        ref={videoRef}
   433→        autoPlay
   434→        playsInline
   435→        muted
   436→        style={{
   437→          position: "absolute",
   438→          top: 0,
   439→          left: 0,
   440→          width: "100%",
   441→          height: "100%",
   442→          objectFit: "cover",
   443→          transform: "scaleX(-1)",
   444→        }}
   445→      />
   446→
   447→      {/* === ATTRACT STATE === */}
   448→      {kioskState === "attract" && (
   449→        <div
   450→          style={{
   451→            position: "absolute",
   452→            inset: 0,
   453→            zIndex: 20,
   454→            display: "flex",
   455→            flexDirection: "column",
   456→            alignItems: "center",
   457→            justifyContent: "center",
   458→            background: "rgba(0,0,0,0.7)",
   459→            backdropFilter: "blur(20px)",
   460→          }}
   461→        >
   462→          <h1
   463→            style={{
   464→              color: "#fff",
   465→              fontSize: "3rem",
   466→              fontWeight: 700,
   467→              marginBottom: 8,
   468→              letterSpacing: "-0.02em",
   469→            }}
   470→          >
   471→            Mirrorless
   472→          </h1>
   473→          <p style={{ color: "rgba(255,255,255,0.6)", fontSize: "1.2rem", marginBottom: 40 }}>
   474→            Your AI stylist
   475→          </p>
   476→
   477→          <div
   478→            style={{
   479→              background: "#fff",
   480→              borderRadius: 16,
   481→              padding: 20,
   482→              marginBottom: 24,
   483→            }}
   484→          >
   485→            <QRCodeSVG
   486→              value={PHONE_URL}
   487→              size={180}
   488→              level="M"
   489→              includeMargin={false}
   490→            />
   491→          </div>
   492→
   493→          <p style={{ color: "rgba(255,255,255,0.4)", fontSize: "0.9rem" }}>
   494→            Scan the QR code with your phone
   495→          </p>
   496→        </div>
   497→      )}
   498→
   499→      {/* === WAITING STATE === */}
   500→      {kioskState === "waiting" && activeUser && (
   501→        <div
   502→          style={{
   503→            position: "absolute",
   504→            inset: 0,
   505→            zIndex: 20,
   506→            display: "flex",
   507→            flexDirection: "column",
   508→            alignItems: "center",
   509→            justifyContent: "center",
   510→            background: "rgba(0,0,0,0.6)",
   511→            backdropFilter: "blur(10px)",
   512→          }}
   513→        >
